/*
 * Zero-length sound placeholders for the xiaozhi compatibility layer.
 *
 * Project Luma streams synthesized PCM from Brain, so the xiaozhi UI prompt
 * sounds are not embedded in the firmware. The compatibility code still
 * references the binary symbols generated by ESP-IDF EMBED_FILES; define them
 * here with start == end to keep those references linkable without carrying
 * unused OGG assets through PlatformIO's generated-source path.
 */

.section .rodata
.balign 4

.macro LUMA_EMPTY_OGG name
.global _binary_\name\()_ogg_start
.global _binary_\name\()_ogg_end
_binary_\name\()_ogg_start:
_binary_\name\()_ogg_end:
.endm

LUMA_EMPTY_OGG 0
LUMA_EMPTY_OGG 1
LUMA_EMPTY_OGG 2
LUMA_EMPTY_OGG 3
LUMA_EMPTY_OGG 4
LUMA_EMPTY_OGG 5
LUMA_EMPTY_OGG 6
LUMA_EMPTY_OGG 7
LUMA_EMPTY_OGG 8
LUMA_EMPTY_OGG 9
